import React, { useState } from 'react'
import useTreeStore from './useTreeStore'
import { GoPencil, GoChevronRight, GoChevronDown } from "react-icons/go";
export const TYPE = {
    FOLDER: 'folder',
    FILE: 'file'
}
function TreeNode({ name, id, type, children, isExpanded }) {
    const expandedIds = useTreeStore((state) => state.expandedIds)
    const setExpandedIds = useTreeStore((state) => state.setExpandedIds)
    const renameNode = useTreeStore((state) => state.renameNode)
    const showChildren = children && children.length > 0 && expandedIds[id]

    const [isEditing, setIsEditing] = useState(false)
    const [inputValue, setInputValue] = useState(name)

    function renderChildren() {
        return (children.map(({ name, id, type, children }) => {
            return (
                <TreeNode key={id} id={id} name={name} type={type} children={children} isExpanded={isExpanded} />
            )
        }))
    }

    function renderer(name, type, isExpanded) {
        const nameDisplay = isEditing
            ? <input
                autoFocus
                value={inputValue}
                onChange={e => setInputValue(e.target.value)}
                onBlur={handleRenameConfirm}
                onKeyDown={handleKeyDown}
                onClick={e => e.stopPropagation()}
              />
            : <span>{name}</span>

        if (type === TYPE.FOLDER) {
            return (<div>
                {nameDisplay}
                {isExpanded ? <GoChevronDown /> : <GoChevronRight />}
            </div>)
        } else {
            return <>{nameDisplay}</>
        }
    }

    function clickHandler(id) {
        setExpandedIds(id)
    }

    function handleEdit(e) {
        e.stopPropagation()
        setIsEditing(true)
        setInputValue(name)
    }

    function handleRenameConfirm() {
        if (inputValue.trim()) renameNode(id, inputValue.trim())
        setIsEditing(false)
    }

    function handleKeyDown(e) {
        if (e.key === 'Enter') handleRenameConfirm()
        if (e.key === 'Escape') setIsEditing(false)
    }

    return (
        <>
            <li key={id}>
                <button className='list-btn' onClick={() => clickHandler(id)}>{renderer(name, type, isExpanded)}</button>
                <button onClick={(e) => handleEdit(e)}><GoPencil /></button>

            </li>
            <ul className='folder'>{showChildren && renderChildren()}</ul>
        </>)

}

export default TreeNode
